 379→            try { return new URL(h.url).hostname === hostname; } 
 380→            catch(e) { return false; }
 381→        });
 382→
 383→        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
 384→        // Les anciens projets ne comptent pas dans cette limite
 385→        if (!isExistingProject && monthlyProjectCount >= limit) {
 386→            // Redirection vers l'onglet Abonnement
