 412→      setMegaStatus('generating');
 413→      megaGenerate(url).then(cache => {
 414→        if (cache) {
 415→          const preGenerated = { status: 'completed' as const, generatedAt: new Date().toISOString(), ...cache };
 416→          setHistory(prev => {
 417→            if (prev.length === 0) return prev;
