 419→            db.update(0, updated);
 420→            return [updated, ...prev.slice(1)];
 421→          });
 422→          setAnalysisData(prev => prev ? { ...prev, preGenerated } : prev);
 423→          setMegaStatus('completed');
 424→        } else {
 425→          setMegaStatus('failed');
 426→        }
 427→      }).catch(() => setMegaStatus('failed'));
 428→
 429→      // Solution mega-generation en arrière-plan (Generate All, Reveal on Credit)
 430→      const auditId = result.timestamp;
 431→      if (!hasVault(auditId)) {
 432→        const failedCriteria = result.recommendations.map(rec => ({
 433→          id: rec.id,
 434→          name: rec.title,
 435→          category: rec.category,
 436→          maxPoints: rec.priority === 'critical' ? 5 : rec.priority === 'high' ? 4 : rec.priority === 'medium' ? 3 : 1,
 437→        }));
 438→        let hostname = url;
 439→        try { hostname = new URL(url).hostname; } catch { /* keep raw */ }
 440→        generateAllSolutions(
 441→          url,
 442→          hostname,
 443→          result.recommendations.map(r => r.title).join('. '),
 444→          failedCriteria,
 445→          [],
 446→          hostname,
 447→          'fr'
 448→        ).then(megaResult => {
 449→          storeInVault(auditId, megaResult);
 450→          console.log('[SolutionMegaGen] Solutions pré-générées et stockées:', megaResult.solutionsCount);
 451→        }).catch(err => {
 452→          console.error('[SolutionMegaGen] Erreur:', err);
 453→        });
 454→      }
 455→
 456→      // Redirection vers Monitoring AEO → onglet Rapport d'Audit
 457→      setResultsTab('details');
 458→      navigateTo('projects');
 459→      setSectionsState({
 460→        optimization: false,
 461→        tools: false
 462→      });
 463→    } catch (error) {
 464→      console.error("Analysis failed", error);
 465→      alert("Erreur lors de l'analyse. Veuillez réessayer.");
 466→    } finally {
 467→      setIsAnalyzing(false);
 468→    }
