 494→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
 495→    const timestamp = new Date().toISOString();
 496→    const solutionWithMeta = { ...solution, timestamp };
 497→
 498→    setAnalysisData(prev => {
 499→        if (!prev || prev.timestamp !== analysisId) return prev;
 500→        
 501→        return {
 502→            ...prev,
 503→            generatedSolutions: {
 504→                ...(prev.generatedSolutions || {}),
 505→                [recommendationId]: solutionWithMeta
 506→            }
 507→        };
 508→    });
 509→
 510→    // We need to find the index in the history to update the DB
 511→    setHistory(prevHistory => {
 512→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
 513→        if (index !== -1) {
 514→            const updatedItem = {
 515→                ...prevHistory[index],
 516→                generatedSolutions: {
 517→                    ...(prevHistory[index].generatedSolutions || {}),
 518→                    [recommendationId]: solutionWithMeta
 519→                }
 520→            };
 521→            // Persist using db service
 522→            const newHistory = [...prevHistory];
 523→            newHistory[index] = updatedItem;
